import{c as t,Q as o,j as a,m as i}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"HavenBot — troubleshooting","description":"Symptom → fix for the most common HavenBot issues.","frontmatter":{"title":"HavenBot — troubleshooting","description":"Symptom → fix for the most common HavenBot issues."},"headers":[],"relativePath":"havenbot/troubleshooting.md","filePath":"havenbot/troubleshooting.md","lastUpdated":1778983454000}'),s={name:"havenbot/troubleshooting.md"};function r(n,e,u,l,h,d){return o(),a("div",null,[...e[0]||(e[0]=[i('<h1 id="havenbot-troubleshooting" tabindex="-1">HavenBot troubleshooting <a class="header-anchor" href="#havenbot-troubleshooting" aria-label="Permalink to &quot;HavenBot troubleshooting&quot;">​</a></h1><p>A symptom-first reference. If your issue isn&#39;t here, ping the MuHaven team or file an issue on GitHub.</p><h2 id="sign-in-session" tabindex="-1">Sign-in &amp; session <a class="header-anchor" href="#sign-in-session" aria-label="Permalink to &quot;Sign-in &amp; session&quot;">​</a></h2><h3 id="sign-in-succeeded-but-the-dashboard-is-empty" tabindex="-1">&quot;Sign in succeeded, but the dashboard is empty.&quot; <a class="header-anchor" href="#sign-in-succeeded-but-the-dashboard-is-empty" aria-label="Permalink to &quot;&quot;Sign in succeeded, but the dashboard is empty.&quot;&quot;">​</a></h3><p>Check the network selector top-right. You may be on a network where your MuHaven wallet doesn&#39;t exist (e.g., signed in on Arb Sepolia but viewing Arb One). Switch to the network where your MuHaven wallet was deployed.</p><h3 id="passkey-dialog-doesn-t-appear" tabindex="-1">&quot;Passkey dialog doesn&#39;t appear.&quot; <a class="header-anchor" href="#passkey-dialog-doesn-t-appear" aria-label="Permalink to &quot;&quot;Passkey dialog doesn&#39;t appear.&quot;&quot;">​</a></h3><ul><li>Confirm the browser supports WebAuthn (Chrome / Edge / Safari / Firefox — current versions).</li><li>On macOS: System Settings → Passwords → enable iCloud Keychain if you want sync.</li><li>On Windows: Settings → Accounts → Sign-in options → enable Windows Hello.</li><li>If the dialog appears for <em>other</em> sites but not MuHaven, your browser may be blocking origin <code>muhaven.app</code>. Allow it.</li></ul><h3 id="i-get-prompted-for-my-passkey-on-every-action-even-in-confirm-per-action-tier" tabindex="-1">&quot;I get prompted for my passkey on every action even in Confirm-per-action tier.&quot; <a class="header-anchor" href="#i-get-prompted-for-my-passkey-on-every-action-even-in-confirm-per-action-tier" aria-label="Permalink to &quot;&quot;I get prompted for my passkey on every action even in Confirm-per-action tier.&quot;&quot;">​</a></h3><p>Your session key expired. Default TTL is 1 hour. The next action will re-install a fresh session key with one passkey prompt.</p><p>If you&#39;re seeing the prompt within an hour of installation, the session-key validator may have been uninstalled (e.g., by <code>/pause</code>). Resume the agent and the next action will mint a fresh one.</p><h3 id="i-m-signed-out-unexpectedly" tabindex="-1">&quot;I&#39;m signed out unexpectedly.&quot; <a class="header-anchor" href="#i-m-signed-out-unexpectedly" aria-label="Permalink to &quot;&quot;I&#39;m signed out unexpectedly.&quot;&quot;">​</a></h3><p>JWT expiry (silent — happens if your tab sits idle past the refresh window). Sign in again.</p><h2 id="funding-buying" tabindex="-1">Funding &amp; buying <a class="header-anchor" href="#funding-buying" aria-label="Permalink to &quot;Funding &amp; buying&quot;">​</a></h2><h3 id="faucet-won-t-dispense-mhusdc" tabindex="-1">&quot;Faucet won&#39;t dispense mhUSDC.&quot; <a class="header-anchor" href="#faucet-won-t-dispense-mhusdc" aria-label="Permalink to &quot;&quot;Faucet won&#39;t dispense mhUSDC.&quot;&quot;">​</a></h3><p>Testnet faucets are rate-limited (typically 1 request per address per 24 hours). Wait, or:</p><ul><li>Try a different faucet (the wizard links to one but <code>https://www.alchemy.com/faucets/arbitrum-sepolia</code> and friends also work).</li><li>Bridge USDC from Sepolia via the canonical Arb bridge, then wrap.</li></ul><h3 id="buy-fails-with-balancetoolow" tabindex="-1">&quot;Buy fails with <code>BalanceTooLow</code>.&quot; <a class="header-anchor" href="#buy-fails-with-balancetoolow" aria-label="Permalink to &quot;&quot;Buy fails with `BalanceTooLow`.&quot;&quot;">​</a></h3><p>Your mhUSDC balance is below the requested amount. The Subscription contract performs a <strong>silent-fail privacy-preserving</strong> check — the cleartext amount is decreased to zero on a balance shortfall but the UserOp still settles. The audit log records the attempt; no funds move.</p><p>To verify your balance, ask HavenBot: &quot;What&#39;s my mhUSDC balance?&quot; — the unseal runs in your browser.</p><h3 id="buy-succeeded-but-my-balance-didn-t-change" tabindex="-1">&quot;Buy succeeded but my balance didn&#39;t change.&quot; <a class="header-anchor" href="#buy-succeeded-but-my-balance-didn-t-change" aria-label="Permalink to &quot;&quot;Buy succeeded but my balance didn&#39;t change.&quot;&quot;">​</a></h3><p>The Arbitrum view-RPC sometimes returns stale data briefly after a write. Wait, refresh. If it persists:</p><ul><li>Check Arbiscan for the tx (the toast links to it).</li><li>Verify the tx didn&#39;t revert (revert reason in Arbiscan logs).</li><li>If the tx succeeded but your dashboard still doesn&#39;t show the balance, file an issue — there may be an indexer lag.</li></ul><h3 id="confirmmodal-shows-decryptforview-errors" tabindex="-1">&quot;ConfirmModal shows <code>decryptForView</code> errors.&quot; <a class="header-anchor" href="#confirmmodal-shows-decryptforview-errors" aria-label="Permalink to &quot;&quot;ConfirmModal shows `decryptForView` errors.&quot;&quot;">​</a></h3><p>Your decrypt permit expired. Refresh the page; HavenBot re-mints the permit on next action. If the error persists, try:</p><ol><li>Sign out, sign back in (forces a fresh permit ceremony).</li><li>If that fails, check <a href="https://api.muhaven.app/health" target="_blank" rel="noreferrer"><code>api.muhaven.app/health</code></a> — the CoFHE threshold network may be having a hiccup.</li></ol><h2 id="chat-behavior" tabindex="-1">Chat behavior <a class="header-anchor" href="#chat-behavior" aria-label="Permalink to &quot;Chat behavior&quot;">​</a></h2><h3 id="havenbot-keeps-asking-me-for-clarification" tabindex="-1">&quot;HavenBot keeps asking me for clarification.&quot; <a class="header-anchor" href="#havenbot-keeps-asking-me-for-clarification" aria-label="Permalink to &quot;&quot;HavenBot keeps asking me for clarification.&quot;&quot;">​</a></h3><p>The LLM is set to strict-enum schemas on every tool. If you ask &quot;buy some <code>&lt;TOKEN&gt;</code>&quot;, HavenBot will ask &quot;how much?&quot; because the <code>amount</code> field is required.</p><p>Phrase your asks concretely: &quot;Buy 50 mhUSDC of <code>&lt;TOKEN&gt;</code>.&quot;</p><h3 id="havenbot-returned-an-answer-in-raw-json" tabindex="-1">&quot;HavenBot returned an answer in raw JSON.&quot; <a class="header-anchor" href="#havenbot-returned-an-answer-in-raw-json" aria-label="Permalink to &quot;&quot;HavenBot returned an answer in raw JSON.&quot;&quot;">​</a></h3><p>Rare — usually the LLM stream was interrupted before it could format. Refresh and re-ask.</p><h3 id="havenbot-says-it-can-t-do-something-i-know-exists" tabindex="-1">&quot;HavenBot says it can&#39;t do something I know exists.&quot; <a class="header-anchor" href="#havenbot-says-it-can-t-do-something-i-know-exists" aria-label="Permalink to &quot;&quot;HavenBot says it can&#39;t do something I know exists.&quot;&quot;">​</a></h3><p>Two possibilities:</p><ol><li><strong>Tier mismatch.</strong> The tool exists but your tier excludes it (e.g., set_policy → Policy-bound is blocked while you&#39;re in Advisory&#39;s onboarding window).</li><li><strong>Role mismatch.</strong> Issuer tools are hidden from investor passkeys. Sign in with your issuer passkey if you have one — see <a href="/get-started/investor-vs-issuer">Investor vs issuer</a>.</li></ol><h3 id="streaming-response-stops-mid-sentence" tabindex="-1">&quot;Streaming response stops mid-sentence.&quot; <a class="header-anchor" href="#streaming-response-stops-mid-sentence" aria-label="Permalink to &quot;&quot;Streaming response stops mid-sentence.&quot;&quot;">​</a></h3><p>Network glitch or LLM timeout. The SSE channel reconnects automatically; if your message isn&#39;t completing, click <strong>Stop</strong> and re-ask.</p><h2 id="confirmmodal" tabindex="-1">ConfirmModal <a class="header-anchor" href="#confirmmodal" aria-label="Permalink to &quot;ConfirmModal&quot;">​</a></h2><h3 id="confirmmodal-opened-but-the-preview-shows-zeros" tabindex="-1">&quot;ConfirmModal opened but the preview shows zeros.&quot; <a class="header-anchor" href="#confirmmodal-opened-but-the-preview-shows-zeros" aria-label="Permalink to &quot;&quot;ConfirmModal opened but the preview shows zeros.&quot;&quot;">​</a></h3><p>The encrypted preview decrypt failed (permit expired, ACL not granted, RPC lag). Cancel and re-ask — HavenBot will re-mint the permit + retry the decrypt.</p><h3 id="confirm-button-is-disabled" tabindex="-1">&quot;Confirm button is disabled.&quot; <a class="header-anchor" href="#confirm-button-is-disabled" aria-label="Permalink to &quot;&quot;Confirm button is disabled.&quot;&quot;">​</a></h3><ul><li><strong>Insufficient mhUSDC</strong> for a buy. The amount-vs-balance check is client-side. Top up.</li><li><strong>Tier doesn&#39;t allow this action.</strong> The modal&#39;s footer explains why (e.g., &quot;Policy-bound caps your daily spend at $500; this would push you to $620&quot;).</li><li><strong>Session key has insufficient remaining allowance.</strong> Pause and resume to mint a fresh key with reset allowances.</li></ul><h3 id="i-clicked-confirm-but-nothing-happened" tabindex="-1">&quot;I clicked Confirm but nothing happened.&quot; <a class="header-anchor" href="#i-clicked-confirm-but-nothing-happened" aria-label="Permalink to &quot;&quot;I clicked Confirm but nothing happened.&quot;&quot;">​</a></h3><p>Browser pop-up blocker may have suppressed the passkey ceremony (Advisory tier prompts the passkey on every action). Allow popups for <code>muhaven.app</code> and retry.</p><h2 id="issuer-flows" tabindex="-1">Issuer flows <a class="header-anchor" href="#issuer-flows" aria-label="Permalink to &quot;Issuer flows&quot;">​</a></h2><h3 id="i-see-investor-tools-but-no-issuer-tools" tabindex="-1">&quot;I see investor tools, but no issuer tools.&quot; <a class="header-anchor" href="#i-see-investor-tools-but-no-issuer-tools" aria-label="Permalink to &quot;&quot;I see investor tools, but no issuer tools.&quot;&quot;">​</a></h3><p>You&#39;re signed in with your <strong>investor</strong> passkey. Sign out, sign back in with the issuer passkey (different passkey per <a href="/get-started/investor-vs-issuer">one passkey, one role</a>).</p><h3 id="issuer-tools-are-visible-but-i-get-403-not-approved-issuer-on-every-commit" tabindex="-1">&quot;Issuer tools are visible but I get 403 NOT_APPROVED_ISSUER on every commit.&quot; <a class="header-anchor" href="#issuer-tools-are-visible-but-i-get-403-not-approved-issuer-on-every-commit" aria-label="Permalink to &quot;&quot;Issuer tools are visible but I get 403 NOT_APPROVED_ISSUER on every commit.&quot;&quot;">​</a></h3><p>Your issuer status isn&#39;t <code>approved</code> yet. Visit <code>/apply-issuer</code> to check; in dev mode it auto-approves but on production it requires manual review.</p><h3 id="distribute-yield-modal-shows-the-wrong-investor-count" tabindex="-1">&quot;Distribute yield modal shows the wrong investor count.&quot; <a class="header-anchor" href="#distribute-yield-modal-shows-the-wrong-investor-count" aria-label="Permalink to &quot;&quot;Distribute yield modal shows the wrong investor count.&quot;&quot;">​</a></h3><p>The investor count is read from <code>InvestorRegistry</code> at propose time. If you added KYC entries recently, the indexer may not have caught up — wait and re-propose.</p><h3 id="unpause-says-my-token-is-already-active" tabindex="-1">&quot;Unpause says my token is already active.&quot; <a class="header-anchor" href="#unpause-says-my-token-is-already-active" aria-label="Permalink to &quot;&quot;Unpause says my token is already active.&quot;&quot;">​</a></h3><p>The tool is idempotent. If your token is already unpaused, refuses with <code>409 ALREADY_ACTIVE</code> — nothing to do.</p><h2 id="pause-resume" tabindex="-1">Pause &amp; resume <a class="header-anchor" href="#pause-resume" aria-label="Permalink to &quot;Pause &amp; resume&quot;">​</a></h2><h3 id="pause-didn-t-take-effect" tabindex="-1">&quot;Pause didn&#39;t take effect.&quot; <a class="header-anchor" href="#pause-didn-t-take-effect" aria-label="Permalink to &quot;&quot;Pause didn&#39;t take effect.&quot;&quot;">​</a></h3><p>The on-chain <code>uninstallPlugin</code> UserOp is fast (≤1 Arb block) but the backend&#39;s reflection of &quot;paused&quot; updates on the next block. Wait and check again.</p><h3 id="resume-failed" tabindex="-1">&quot;Resume failed.&quot; <a class="header-anchor" href="#resume-failed" aria-label="Permalink to &quot;&quot;Resume failed.&quot;&quot;">​</a></h3><p>Resume re-installs the session-key validator and signs with your passkey. If the passkey ceremony was cancelled, resume errors with <code>401 PASSKEY_REQUIRED</code>. Re-try and complete the passkey prompt.</p><h2 id="help-isn-t-here" tabindex="-1">Help isn&#39;t here? <a class="header-anchor" href="#help-isn-t-here" aria-label="Permalink to &quot;Help isn&#39;t here?&quot;">​</a></h2><ul><li>Read the surface-level docs (<a href="/havenbot/overview">HavenBot overview</a>) and <a href="/reference/tool-catalog">Tool catalog</a>.</li><li>Check the <a href="https://github.com/hasToDev/muhaven/blob/master/docs/AGENT_DESIGN.md" target="_blank" rel="noreferrer"><code>docs/AGENT_DESIGN.md</code></a> in the GitHub repo for the engineering-level reference.</li><li>File an issue at <a href="https://github.com/hasToDev/muhaven/issues" target="_blank" rel="noreferrer">github.com/hasToDev/muhaven/issues</a>.</li></ul>',59)])])}const m=t(s,[["render",r]]);export{p as __pageData,m as default};
